import React, { useState, useEffect, useRef } from 'react';
import { mysqlAPI } from '../services/mysqlApi';
import ResultsPanel from '../components/ResultsPanel';

const SUGGESTIONS = [
  "Show all customers",
  "Show total orders by region",
  "Top 5 customers by total spend",
  "Show all confirmed orders",
  "Count orders by status",
  "Show orders joined with customer names",
  "Average order amount by region",
  "Show customers from North America",
];

export default function MySQLPage() {
  const [host, setHost] = useState('127.0.0.1');
  const [port, setPort] = useState(3307);
  const [database, setDatabase] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [tables, setTables] = useState([]);
  const [selectedTables, setSelectedTables] = useState([]);
  const [connected, setConnected] = useState(false);
  const [connecting, setConnecting] = useState(false);
  const [question, setQuestion] = useState('');
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [dbInfo, setDbInfo] = useState(null);
  const bottomRef = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [history]);

  const handleConnect = async () => {
    if (!host || !database || !username || !password) {
      setError('Please fill in all connection fields');
      return;
    }
    setConnecting(true);
    setError('');
    try {
      await mysqlAPI.testConnection({ host, port, database, username, password });
      const res = await mysqlAPI.listTables({ host, port, database, username, password });
      setTables(res.data.tables);
      setSelectedTables(res.data.tables);
      setConnected(true);
      setDbInfo({ host, port, database });
    } catch (e) {
      setError(e.response?.data?.detail || 'Connection failed');
    } finally {
      setConnecting(false);
    }
  };

  const handleDisconnect = () => {
    setConnected(false);
    setTables([]);
    setSelectedTables([]);
    setDbInfo(null);
    setHistory([]);
  };

  const toggleTable = (table) => {
    setSelectedTables(prev =>
      prev.includes(table) ? prev.filter(t => t !== table) : [...prev, table]
    );
  };

  const handleSubmit = async () => {
    if (!question.trim() || selectedTables.length === 0) return;
    const q = question.trim();
    setQuestion('');
    setLoading(true);
    setHistory(prev => [...prev, { type: 'user', content: q }]);
    try {
      const endpoint = selectedTables.length > 1
        ? mysqlAPI.nlQueryJoin
        : mysqlAPI.nlQuery;
      const res = await endpoint({
        host, port, database, username, password,
        question: q,
        tables: selectedTables
      });
      setHistory(prev => [...prev, {
        type: 'result',
        question: q,
        content: res.data
      }]);
    } catch (e) {
      setHistory(prev => [...prev, {
        type: 'error',
        content: e.response?.data?.detail || 'Query failed'
      }]);
    } finally {
      setLoading(false);
    }
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSubmit();
    }
  };

  return (
    <div style={{ display: 'flex', height: '100vh', overflow: 'hidden', background: '#f8f8f6' }}>

      {/* ── Left Panel ── */}
      <div style={{
        width: 260, minWidth: 260, background: '#0f1117',
        display: 'flex', flexDirection: 'column', padding: 16,
        overflowY: 'auto', gap: 12
      }}>
        <div style={{ color: '#fff', fontWeight: 700, fontSize: 15, marginBottom: 4 }}>
          🐬 MySQL Connection
        </div>

        {!connected ? (
          <>
            {/* Connection Form */}
            {[
              { label: 'Host', value: host, set: setHost, placeholder: '127.0.0.1' },
              { label: 'Port', value: port, set: v => setPort(Number(v)), placeholder: '3307' },
              { label: 'Database', value: database, set: setDatabase, placeholder: 'test_db' },
              { label: 'Username', value: username, set: setUsername, placeholder: 'da_user' },
            ].map(({ label, value, set, placeholder }) => (
              <div key={label}>
                <div style={{ color: '#9ca3af', fontSize: 11, marginBottom: 3 }}>{label}</div>
                <input
                  value={value}
                  onChange={e => set(e.target.value)}
                  placeholder={placeholder}
                  style={{
                    width: '100%', background: '#1f2937', border: '1px solid #374151',
                    borderRadius: 6, color: '#fff', padding: '6px 10px', fontSize: 13,
                    boxSizing: 'border-box'
                  }}
                />
              </div>
            ))}
            <div>
              <div style={{ color: '#9ca3af', fontSize: 11, marginBottom: 3 }}>Password</div>
              <input
                type="password"
                value={password}
                onChange={e => setPassword(e.target.value)}
                placeholder="password"
                style={{
                  width: '100%', background: '#1f2937', border: '1px solid #374151',
                  borderRadius: 6, color: '#fff', padding: '6px 10px', fontSize: 13,
                  boxSizing: 'border-box'
                }}
              />
            </div>
            {error && (
              <div style={{ color: '#f87171', fontSize: 12, background: '#1f1f1f', padding: 8, borderRadius: 6 }}>
                {error}
              </div>
            )}
            <button
              onClick={handleConnect}
              disabled={connecting}
              style={{
                background: '#6366f1', color: '#fff', border: 'none',
                borderRadius: 8, padding: '8px 0', fontWeight: 600,
                cursor: connecting ? 'not-allowed' : 'pointer', fontSize: 13,
                opacity: connecting ? 0.7 : 1
              }}
            >
              {connecting ? 'Connecting...' : 'Connect'}
            </button>
          </>
        ) : (
          <>
            {/* Connected State */}
            <div style={{
              background: '#052e16', border: '1px solid #166534',
              borderRadius: 8, padding: 10
            }}>
              <div style={{ color: '#4ade80', fontSize: 12, fontWeight: 600 }}>
                ● Connected
              </div>
              <div style={{ color: '#9ca3af', fontSize: 11, marginTop: 4 }}>
                {dbInfo?.host}:{dbInfo?.port}/{dbInfo?.database}
              </div>
            </div>

            {/* Table Selector */}
            <div>
              <div style={{
                display: 'flex', justifyContent: 'space-between',
                alignItems: 'center', marginBottom: 6
              }}>
                <span style={{ color: '#9ca3af', fontSize: 11 }}>
                  Tables ({tables.length})
                </span>
                <div style={{ display: 'flex', gap: 6 }}>
                  <button onClick={() => setSelectedTables(tables)}
                    style={{ color: '#6366f1', background: 'none', border: 'none', fontSize: 11, cursor: 'pointer' }}>
                    All
                  </button>
                  <button onClick={() => setSelectedTables([])}
                    style={{ color: '#9ca3af', background: 'none', border: 'none', fontSize: 11, cursor: 'pointer' }}>
                    None
                  </button>
                </div>
              </div>
              {tables.map(table => (
                <label key={table} style={{
                  display: 'flex', alignItems: 'center', gap: 8,
                  padding: '5px 8px', borderRadius: 6, cursor: 'pointer',
                  background: selectedTables.includes(table) ? '#1e1b4b' : 'transparent',
                  marginBottom: 2
                }}>
                  <input
                    type="checkbox"
                    checked={selectedTables.includes(table)}
                    onChange={() => toggleTable(table)}
                    style={{ accentColor: '#6366f1' }}
                  />
                  <span style={{ color: '#e5e7eb', fontSize: 12 }}>{table}</span>
                </label>
              ))}
            </div>

            {/* Multi-table hint */}
            {selectedTables.length > 1 && (
              <div style={{
                background: '#1e1b4b', border: '1px solid #4338ca',
                borderRadius: 6, padding: 8
              }}>
                <div style={{ color: '#a5b4fc', fontSize: 11 }}>
                  {selectedTables.length} tables — auto JOIN enabled
                </div>
              </div>
            )}

            {/* Suggestions */}
            <div>
              <div style={{ color: '#9ca3af', fontSize: 11, marginBottom: 6 }}>
                Suggestions
              </div>
              {SUGGESTIONS.map(s => (
                <div
                  key={s}
                  onClick={() => setQuestion(s)}
                  style={{
                    color: '#d1d5db', fontSize: 11, padding: '5px 8px',
                    borderRadius: 6, cursor: 'pointer', marginBottom: 2,
                    background: '#1f2937', border: '1px solid #374151'
                  }}
                  onMouseEnter={e => e.target.style.background = '#374151'}
                  onMouseLeave={e => e.target.style.background = '#1f2937'}
                >
                  {s}
                </div>
              ))}
            </div>

            <button
              onClick={handleDisconnect}
              style={{
                background: 'transparent', color: '#9ca3af',
                border: '1px solid #374151', borderRadius: 8,
                padding: '6px 0', cursor: 'pointer', fontSize: 12,
                marginTop: 'auto'
              }}
            >
              Disconnect
            </button>
          </>
        )}
      </div>

      {/* ── Right Panel ── */}
      <div style={{
        flex: 1, display: 'flex', flexDirection: 'column',
        overflow: 'hidden'
      }}>
        {/* Header */}
        <div style={{
          background: '#0f1117', padding: '14px 24px',
          display: 'flex', alignItems: 'center', gap: 10,
          borderBottom: '1px solid #1f2937'
        }}>
          <span style={{ fontSize: 20 }}>🐬</span>
          <div>
            <div style={{ color: '#fff', fontWeight: 700, fontSize: 15 }}>
              MySQL Query
            </div>
            <div style={{ color: '#6b7280', fontSize: 12 }}>
              {connected
                ? `Connected to ${dbInfo?.database} — ${selectedTables.length} table(s) selected`
                : 'Connect to a MySQL database to start querying'}
            </div>
          </div>
        </div>

        {/* Chat History */}
        <div style={{
          flex: 1, overflowY: 'auto', padding: '20px 24px',
          display: 'flex', flexDirection: 'column', gap: 16
        }}>
          {history.length === 0 && (
            <div style={{
              textAlign: 'center', color: '#9ca3af',
              marginTop: 60, fontSize: 14
            }}>
              {connected
                ? '💬 Ask a question about your MySQL data'
                : '🔌 Connect to a MySQL database using the panel on the left'}
            </div>
          )}

          {history.map((item, i) => (
            <div key={i}>
              {item.type === 'user' && (
                <div style={{ display: 'flex', justifyContent: 'flex-end' }}>
                  <div style={{
                    background: '#6366f1', color: '#fff', borderRadius: '16px 16px 4px 16px',
                    padding: '10px 16px', maxWidth: '70%', fontSize: 14
                  }}>
                    {item.content}
                  </div>
                </div>
              )}
              {item.type === 'result' && (
                <div style={{
                  background: '#fff', borderRadius: 12, border: '1px solid #e5e7eb',
                  overflow: 'hidden', boxShadow: '0 1px 4px rgba(0,0,0,0.06)'
                }}>
                  <ResultsPanel
                    result={item.content}
                    question={item.question}
                  />
                </div>
              )}
              {item.type === 'error' && (
                <div style={{
                  background: '#fef2f2', border: '1px solid #fecaca',
                  borderRadius: 10, padding: '12px 16px',
                  color: '#dc2626', fontSize: 13
                }}>
                  ⚠️ {item.content}
                </div>
              )}
            </div>
          ))}

          {loading && (
            <div style={{ display: 'flex', gap: 6, padding: '8px 0' }}>
              {[0, 1, 2].map(i => (
                <div key={i} style={{
                  width: 8, height: 8, borderRadius: '50%',
                  background: '#6366f1',
                  animation: `bounce 1.2s ease-in-out ${i * 0.2}s infinite`
                }} />
              ))}
            </div>
          )}
          <div ref={bottomRef} />
        </div>

        {/* Input Bar */}
        <div style={{
          padding: '12px 24px', background: '#fff',
          borderTop: '1px solid #e5e7eb'
        }}>
          <div style={{
            display: 'flex', gap: 10, alignItems: 'flex-end',
            background: '#f9fafb', border: '1px solid #e5e7eb',
            borderRadius: 12, padding: '8px 12px'
          }}>
            <textarea
              value={question}
              onChange={e => setQuestion(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder={connected
                ? "Ask a question about your MySQL data..."
                : "Connect to a database first..."}
              disabled={!connected || loading}
              rows={1}
              style={{
                flex: 1, border: 'none', background: 'transparent',
                resize: 'none', outline: 'none', fontSize: 14,
                color: '#111827', fontFamily: 'inherit',
                lineHeight: 1.5
              }}
            />
            <button
              onClick={handleSubmit}
              disabled={!connected || loading || !question.trim()}
              style={{
                background: '#6366f1', color: '#fff', border: 'none',
                borderRadius: 8, padding: '8px 16px', fontWeight: 600,
                cursor: 'pointer', fontSize: 13,
                opacity: (!connected || loading || !question.trim()) ? 0.5 : 1
              }}
            >
              Send
            </button>
          </div>
          <div style={{ color: '#9ca3af', fontSize: 11, marginTop: 6, textAlign: 'center' }}>
            Enter to send · Shift+Enter for new line · Powered by Gemini 2.0 Flash
          </div>
        </div>
      </div>

      <style>{`
        @keyframes bounce {
          0%, 80%, 100% { transform: translateY(0); }
          40% { transform: translateY(-8px); }
        }
      `}</style>
    </div>
  );
}
